SELECT * FROM ( SELECT RANK() OVER(ORDER BY SEQ DESC) AS IDX ,SEQ ,GET_CCD_NAME(KIND, #{LANG_CD}) AS KIND ,TITLE ,CONTENT ,ANSWER ,REG_ID ,REG_NAME ,GET_CCD_NAME(STATE, #{LANG_CD}) AS STATE ,REG_DT ,END_DT ,ANS_ID ,ANS_NAME ,( SELECT COUNT(*) FROM NIC90B_2 WHERE BOARD_SEQ = C_QA.SEQ AND BOARD_ID = 'AML_02' ) AS FILE_ATT_YN ,VIEW_COUNT FROM C_QA WHERE 1 = 1 AND NVL(PKG_NAME, 'AML') = #{PKG_NAME}
