SELECT * FROM ( SELECT A.JOB_ID ,A.PARENT_JOBID AS PARENT_JOB_ID ,A.JOB_NM AS JOB_NM ,TO_CHAR(B.STRT_DY_TM, 'YYYY-MM-DD HH24:MI:SS') AS STRT_DY_TM ,TO_CHAR(B.END_DY_TM, 'YYYY-MM-DD HH24:MI:SS') AS END_DY_TM ,B.JOB_ST_CD AS JOB_ST_CD ,TO_CHAR(NVL(B.HNDL_DY_TM,A.HNDL_DY_TM), 'YYYY-MM-DD HH24:MI:SS') AS HNDL_DY_TM ,FN_CDINFO_VAR('USER',NVL(B.HNDL_P_ENO,A.HNDL_P_ENO),'' ) AS HNDL_P_ENO_NM ,B.LAST_YN ,A.DISPLAY_ORDER ,A.PROGRAM_NM ,A.DESC1 ,A.DEPTH ,A.USE_YN ,SCHEDULE_YN ,CRON_EXP FROM NIC93B A, ( SELECT * FROM NIC93B_LOG WHERE (JOB_DT,JOB_SEQ, JOB_ID) IN ( SELECT MAX(AA.JOB_DT) ,MAX(AA.JOB_SEQ) ,JOB_ID FROM NIC93B_LOG AA WHERE JOB_DT BETWEEN #{startDate} || '000000' AND #{endDate} || '235959' GROUP BY JOB_ID ) ) B WHERE A.JOB_ID = B.JOB_ID(+) ) WHERE 1=1 -- AND PARENT_JOB_ID NOT IN ('00_AML')
AND USE_YN = #{USE_YN}
ORDER BY DISPLAY_ORDER

SELECT A.DEP_ID ,A.PAR_DEP_ID ,CASE WHEN PAR_DEP_ID = -1 THEN (SELECT DISPLAY_NM FROM C_CD_NM WHERE CD_ID = 'FDS_F002' AND LANG_CD = 'ko-KR') ELSE (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_ID = A.PAR_DEP_ID) END AS PAR_DEP_NM ,A.DEP_TITLE ,A.DEP_DESC ,A.DEP_TP_CD ,(SELECT DISPLAY_NM FROM C_CD_NM WHERE CD_ID = A.DEP_TP_CD AND LANG_CD = 'ko-KR' ) AS DEP_TP_NM ,A.DISPLAY_DEPTH ,A.DISPLAY_ORDER ,A.CRE_ID ,(SELECT USER_NM FROM C_USER WHERE USER_ID = A.CRE_ID ) AS CRE_NM ,A.CRE_DT ,A.UPD_ID ,(SELECT USER_NM FROM C_USER WHERE USER_ID = A.UPD_ID ) AS UPD_NM ,A.UPD_DT ,(SELECT CASE WHEN COUNT(*) > 0 THEN 'Y' ELSE 'N' END FROM C_DEP_INFO WHERE PAR_DEP_ID = A.DEP_ID AND ROWNUM < 2) AS CHILD_YN FROM C_DEP_INFO A WHERE A.DEP_ID >= 0 AND TO_CHAR(PAR_DEP_ID) LIKE #{PAR_DEP_ID}
AND A.DEP_TITLE LIKE '%' || #{DEP_TITLE} || '%'
ORDER BY DISPLAY_ORDER

